{
  "schemaVersion": 3,
  "judgeId": "judge_2",
  "batchIndex": 1,
  "comparisons": [
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "c4_rock_pool_tides",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 có vòng lặp thưởng rõ ràng hơn thông qua việc chế tạo công cụ từ phế liệu và tái đầu tư. c4 thiên về khai thác sức lực cá nhân, khó mở rộng quy mô theo đúng chất nam tần làm giàu."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "c5_shrimp_paste",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 lồng ghép tốt hơn yếu tố am hiểu tập tính biển (con nước, rạn đá) vào kỹ năng thủ công. Cơ chế bảo vệ nguồn lợi ở chương 21-30 của c2 cũng tự nhiên và gắn kết với nghề nghiệp hơn c5."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "c6_handline_bait",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 phù hợp với nhịp độ 'ấm lên từng bước' của gia đình. c6 mang tính may rủi và đối mặt hiểm cảnh cao, không tạo ra cảm giác bền vững và nhẹ nhàng như việc đặt lồng bẫy."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "c7_live_seafood_transport",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 tập trung vào sản xuất và đánh bắt tại địa phương, khớp với domain 'huyện biển' hơn là c7 vốn thiên về logistics và vận chuyển đường dài."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "c8_light_luring_squid",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 tận dụng nguyên liệu tại chỗ (tre vụn) tốt hơn c8 vốn phụ thuộc vào dầu hỏa - một vật tư khan hiếm và đắt đỏ thời bấy giờ, làm giảm tính agency của nhân vật."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "c9_oyster_spat_poles",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 đạt được thành quả sớm ở chương 3 (có tiền mua gạo), trong khi c9 có độ trễ lớn do đặc thù nuôi trồng, không thỏa mãn tốt yêu cầu 'khoái hoạt' và 'thành quả sớm'."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "c10_net_modifications",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 kết hợp cả kỹ năng chế tạo và trực tiếp đi biển, tạo ra nhiều tình huống 'agency' hơn là chỉ ngồi vá lưới trên bờ như c10."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "dt_01_concept_01",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 tập trung vào nghề biển cốt lõi, phù hợp với độc giả nam tần thích làm giàu bằng tay nghề kỹ thuật hơn là hướng ẩm thực gia đình của dt_01_concept_01."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "dt_01_concept_02",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 sử dụng tri thức dân gian và quan sát thực tế, tạo cảm giác 'niên đại Việt' thuần chất hơn là việc áp dụng kiến thức vi sinh hiện đại của dt_01_concept_02."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "dt_01_concept_03",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 có cơ chế 'mẻ hàng đầu' và 'bữa cơm đủ' ở chương 1-5 rất sắc nét thông qua việc bắt ghẹ, trong khi dt_01_concept_03 thiên về sửa chữa công cụ cho người khác."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "dt_01_concept_04",
      "winnerId": "c2_bamboo_traps",
      "reason": "Sản phẩm ghẹ xanh của c2 có giá trị thị trường cao và dễ tạo ra vòng lặp 'tái đầu tư' mạnh mẽ hơn so với mặt hàng rong biển của dt_01_concept_04."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "dt_01_concept_05",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 kích hoạt hành động chủ động ngay từ chương 1 (đan lồng), tạo cảm giác nhịp đọc nhanh và có agency hơn việc đi thu gom trấu giữ lạnh của dt_01_concept_05."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "dt_01_concept_06",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 phù hợp với quy mô 'đánh bắt ven bờ nhỏ' của domain. dt_01_concept_06 thiên về kỹ thuật đóng tàu, có phần hơi vĩ mô so với yêu cầu 'gia đình ấm lên từng bước'."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "dt_01_concept_07",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 là câu chuyện về sản xuất và kỹ năng biển, trong khi dt_01_concept_07 thiên về marketing, ít mang lại cảm giác 'khoái hoạt' từ việc chinh phục biển cả."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "dt_01_concept_08",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 có tính 'agency' cao hơn khi nhân vật tự tạo ra công cụ (lồng bẫy), thay vì chỉ dựa vào việc nhớ lại vị trí bãi sò như dt_01_concept_08."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "dt_01_concept_09",
      "winnerId": "c2_bamboo_traps",
      "reason": "c2 có sự biến hóa về loài hải sản và kỹ thuật bẫy trong 30 chương tốt hơn, trong khi nghề muối của dt_01_concept_09 dễ bị lặp lại và phụ thuộc quá nhiều vào thời tiết."
    },
    {
      "leftId": "c2_bamboo_traps",
      "rightId": "dt_01_concept_10",
      "winnerId": "c2_bamboo_traps",
      "reason": "dt_01_concept_10 mang hơi hướng hiện đại, không phù hợp với bối cảnh thị trường hóa ban đầu cuối thập niên 80 như c2."
    },
    {
      "leftId": "c3_sun_drying_fish",
      "rightId": "c4_rock_pool_tides",
      "winnerId": "c3_sun_drying_fish",
      "reason": "c3 khai thác tốt cơ chế 'phân loại và chế biến sản lượng bị đánh giá thấp' (cá nục ế), tạo ra giá trị gia tăng rõ rệt và vòng lặp kinh tế bền vững hơn c4."
    },
    {
      "leftId": "c3_sun_drying_fish",
      "rightId": "c5_shrimp_paste",
      "winnerId": "c3_sun_drying_fish",
      "reason": "c3 có mâu thuẫn nội tại và rủi ro (thời tiết, cửa hàng quốc doanh) được xây dựng kịch tính hơn, đồng thời sản phẩm cá một nắng mang tính đặc sản cao hơn."
    },
    {
      "leftId": "c3_sun_drying_fish",
      "rightId": "c6_handline_bait",
      "winnerId": "c3_sun_drying_fish",
      "reason": "c3 thể hiện rõ quá trình thị trường hóa ban đầu thông qua việc ký gửi hàng vào bách hóa huyện, khớp với domain opportunity hơn là việc câu cá đơn lẻ của c6."
    }
  ]
}
